-- DDL --

DROP SCHEMA IF EXISTS TikTakTuk CASCADE;

CREATE SCHEMA TikTakTuk;

SET SEARCH_PATH TO TikTakTuk;

-- CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE TABLE USER_ACCOUNT (
user_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
username VARCHAR(100) UNIQUE NOT NULL,
password VARCHAR(255) NOT NULL
);

CREATE TABLE ROLE(
role_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
role_name VARCHAR(50) UNIQUE NOT NULL
);

CREATE TABLE ACCOUNT_ROLE(
role_id UUID,
user_id UUID,
PRIMARY KEY (role_id, user_id),
FOREIGN KEY (role_id) REFERENCES ROLE(role_id)
ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (user_id) REFERENCES USER_ACCOUNT(user_id)
ON DELETE CASCADE ON UPDATE CASCADE
);

CREATE TABLE CUSTOMER(
customer_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
full_name VARCHAR(100) NOT NULL,
phone_number VARCHAR(20),
user_id UUID UNIQUE NOT NULL,
FOREIGN KEY (user_id) REFERENCES USER_ACCOUNT(user_id)
ON DELETE CASCADE ON UPDATE CASCADE
);

CREATE TABLE ORGANIZER(
organizer_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
organizer_name VARCHAR(100) NOT NULL,
contact_email VARCHAR(100),
user_id UUID UNIQUE NOT NULL,
FOREIGN KEY (user_id) REFERENCES USER_ACCOUNT(user_id)
ON DELETE CASCADE ON UPDATE CASCADE
);

CREATE TABLE VENUE(
venue_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
venue_name VARCHAR(100) NOT NULL,
capacity INTEGER NOT NULL DEFAULT 1,
address TEXT NOT NULL,
city VARCHAR(100) NOT NULL,
jenis_seating VARCHAR(20) NOT NULL,
CONSTRAINT capacity_check CHECK (capacity > 0),
CONSTRAINT jenis_seating_check CHECK (jenis_seating IN ('Free Seating', 'Reserved Seating'))
);

CREATE TABLE SEAT(
seat_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
section VARCHAR(50) NOT NULL,
seat_number VARCHAR(10) NOT NULL,
row_number VARCHAR(10) NOT NULL,
venue_id UUID NOT NULL,
FOREIGN KEY (venue_id) REFERENCES VENUE(venue_id)
ON DELETE CASCADE ON UPDATE CASCADE
);

CREATE TABLE EVENT(
event_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
event_datetime TIMESTAMP NOT NULL,
event_title VARCHAR(200) NOT NULL,
venue_id UUID NOT NULL,
organizer_id UUID NOT NULL,
FOREIGN KEY (venue_id) REFERENCES VENUE(venue_id)
ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (organizer_id) REFERENCES ORGANIZER(organizer_id)
ON DELETE RESTRICT ON UPDATE CASCADE
);

CREATE TABLE ARTIST(
artist_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
name VARCHAR(100) NOT NULL,
genre VARCHAR(100)
);

CREATE TABLE EVENT_ARTIST(
event_id UUID,
artist_id UUID,
role VARCHAR(100),
PRIMARY KEY (event_id, artist_id),
FOREIGN KEY (event_id) REFERENCES EVENT(event_id)
ON DELETE CASCADE ON UPDATE CASCADE,
FOREIGN KEY (artist_id) REFERENCES ARTIST(artist_id)
ON DELETE RESTRICT ON UPDATE CASCADE
);

CREATE TABLE TICKET_CATEGORY(
category_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
category_name VARCHAR(50) NOT NULL,
quota INTEGER NOT NULL DEFAULT 1,
price NUMERIC(12,2) NOT NULL DEFAULT 0,
tevent_id UUID NOT NULL,
FOREIGN KEY (tevent_id) REFERENCES EVENT(event_id)
ON DELETE CASCADE ON UPDATE CASCADE,
CONSTRAINT quota_check CHECK(quota > 0),
CONSTRAINT price_check CHECK(price >=0)
);

CREATE TABLE "ORDER"(
order_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
order_date TIMESTAMP NOT NULL,
payment_status VARCHAR(20) NOT NULL,
total_amount NUMERIC(12,2) NOT NULL DEFAULT 0,
customer_id UUID NOT NULL,
FOREIGN KEY (customer_id) REFERENCES CUSTOMER(customer_id)
ON DELETE RESTRICT ON UPDATE CASCADE,
CONSTRAINT totalamount_check CHECK(total_amount >= 0)
);

CREATE TABLE TICKET(
ticket_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
ticket_code VARCHAR(100) UNIQUE NOT NULL,
tcategory_id UUID NOT NULL,
torder_id UUID NOT NULL,
FOREIGN KEY (tcategory_id) REFERENCES TICKET_CATEGORY(category_id)
ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (torder_id) REFERENCES "ORDER"(order_id)
ON DELETE RESTRICT ON UPDATE CASCADE
);

CREATE TABLE HAS_RELATIONSHIP(
seat_id UUID,
ticket_id UUID,
PRIMARY KEY(seat_id, ticket_id),
FOREIGN KEY (seat_id) REFERENCES SEAT(seat_id)
ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (ticket_id) REFERENCES TICKET(ticket_id)
ON DELETE CASCADE ON UPDATE CASCADE
);

CREATE TABLE PROMOTION(
promotion_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
promo_code VARCHAR(50) UNIQUE NOT NULL,
discount_type VARCHAR(20) NOT NULL DEFAULT 'NOMINAL',
discount_value NUMERIC(12,2) NOT NULL DEFAULT 1,
start_date DATE NOT NULL,
end_date DATE NOT NULL,
usage_limit INTEGER NOT NULL DEFAULT 1,
CONSTRAINT discounttype_check CHECK(discount_type IN('NOMINAL', 'PERCENTAGE')),
CONSTRAINT discountvalue_check CHECK(discount_value > 0),
CONSTRAINT usagelimit_check CHECK(usage_limit > 0)
);

CREATE TABLE ORDER_PROMOTION(
order_promotion_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
promotion_id UUID NOT NULL,
order_id UUID NOT NULL,
FOREIGN KEY (promotion_id) REFERENCES PROMOTION(promotion_id)
ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (order_id) REFERENCES "ORDER"(order_id)
ON DELETE CASCADE ON UPDATE CASCADE
);


-- TRIGGERS --

CREATE OR REPLACE FUNCTION check_seat_delete_func() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF EXISTS (SELECT 1 FROM HAS_RELATIONSHIP WHERE seat_id = OLD.seat_id) THEN
        RAISE EXCEPTION 'Kursi % - Baris % No. % tidak dapat dihapus karena sudah terisi.', 
                        OLD.section, OLD.row_number, OLD.seat_number;
    END IF;
    RETURN OLD;
END;
$$;

CREATE OR REPLACE FUNCTION check_ticket_quota_func() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_quota INTEGER;
    v_sold INTEGER;
    v_category_name VARCHAR;
BEGIN
    SELECT quota, category_name INTO v_quota, v_category_name
    FROM TICKET_CATEGORY WHERE category_id = NEW.tcategory_id;
    SELECT COUNT(*) INTO v_sold FROM TICKET WHERE tcategory_id = NEW.tcategory_id;
    IF v_sold >= v_quota THEN
        RAISE EXCEPTION 'Kuota kategori tiket "%%" sudah penuh. Tidak dapat membuat tiket baru.', 
                        v_category_name;
    END IF;
    RETURN NEW;
END;
$$;

CREATE TRIGGER trg_check_seat_delete
    BEFORE DELETE ON SEAT
    FOR EACH ROW EXECUTE FUNCTION check_seat_delete_func();

CREATE TRIGGER trg_check_ticket_quota
    BEFORE INSERT ON TICKET
    FOR EACH ROW EXECUTE FUNCTION check_ticket_quota_func();

